// UART Transmitter - 9600 baud
module RefModule(

                address,
                clock,
                reset_n,


                readdata
             )
;output  [ 31: 0] readdata;
  input            address;
  input            clock;
  input            reset_n;

  wire    [ 31: 0] readdata;

  assign readdata = address ? 1419000801 : 2899645186;

endmodule
